class Piece:
    def __init__(self, color):
        self.color = color

class PlainPiece(Piece):
    pass

class King(PlainPiece):
    pass

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.grid[i][j] = PlainPiece('black')
        for i in range(5, 8):
            for j in range(8):
                if (i + j) % 2 == 1:
                    self.grid[i][j] = PlainPiece('white')

    def display(self):
        for row in self.grid:
            print(" ".join(["P" if piece else "-" for piece in row]))
